import '@shelex/cypress-allure-plugin';

// Preserve cookies across tests for session management
Cypress.Cookies.defaults({
  preserve: ['session_id', 'auth_token', 'connect.sid']
});

// Global before hook
before(() => {
  cy.log('Starting Cypress + BDD Cucumber test suite for AG-Helix');
});

// Global after hook
after(() => {
  cy.log('Completed Cypress + BDD Cucumber test suite');
});

// Fail fast on uncaught exceptions (optional, can be disabled for flaky apps)
Cypress.on('uncaught:exception', (err, runnable) => {
  // Return false to prevent test failure on uncaught exceptions
  // Customize this based on client application behavior
  if (err.message.includes('ResizeObserver') || err.message.includes('Script error')) {
    return false;
  }
  return true;
});

// Custom command: Login via API (faster than UI for setup)
Cypress.Commands.add('loginViaAPI', (username, password) => {
  const baseUrl = Cypress.env('BASE_URL') || Cypress.config('baseUrl');
  cy.request({
    method: 'POST',
    url: `${baseUrl}/login`,
    body: { username, password },
    failOnStatusCode: false
  }).then((response) => {
    if (response.status === 200 && response.body.token) {
      window.localStorage.setItem('authToken', response.body.token);
    }
  });
});

// Custom command: Clear local storage and cookies
Cypress.Commands.add('clearSession', () => {
  cy.clearCookies();
  cy.clearLocalStorage();
});

